import { onDestroy } from 'svelte';

export interface DebouncedCallback<TArgs extends unknown[]> {
	(...args: TArgs): void;
	cancel: () => void;
	flush: () => void;
}

export function useDebouncedCallback<TArgs extends unknown[]>(
	callback: (...args: TArgs) => void,
	delay = 300
): DebouncedCallback<TArgs> {
	let timeoutId: ReturnType<typeof setTimeout> | null = null;
	let lastArgs: TArgs | null = null;

	const debounced = ((...args: TArgs) => {
		lastArgs = args;

		if (timeoutId) {
			clearTimeout(timeoutId);
		}

		timeoutId = setTimeout(() => {
			timeoutId = null;
			if (lastArgs) {
				callback(...lastArgs);
				lastArgs = null;
			}
		}, delay);
	}) as DebouncedCallback<TArgs>;

	debounced.cancel = () => {
		if (timeoutId) {
			clearTimeout(timeoutId);
			timeoutId = null;
		}
		lastArgs = null;
	};

	debounced.flush = () => {
		if (!lastArgs) return;

		if (timeoutId) {
			clearTimeout(timeoutId);
			timeoutId = null;
		}

		callback(...lastArgs);
		lastArgs = null;
	};

	onDestroy(debounced.cancel);

	return debounced;
}

import type { Column } from '@tanstack/table-core';

export type RangeValue = [number, number];

export function isValidRangeValue(value: unknown): value is RangeValue {
	return (
		Array.isArray(value) &&
		value.length === 2 &&
		typeof value[0] === 'number' &&
		typeof value[1] === 'number' &&
		!Number.isNaN(value[0]) &&
		!Number.isNaN(value[1])
	);
}

export function parseRangeFilterValue(value: unknown, fallback: RangeValue): RangeValue {
	if (isValidRangeValue(value)) {
		return value;
	}

	if (Array.isArray(value) && value.length >= 2) {
		const rawMin = value[0];
		const rawMax = value[1];
		if (rawMin === '' && rawMax === '') {
			return fallback;
		}

		const min =
			rawMin === '' || rawMin === undefined ? fallback[0] : Number(rawMin);
		const max =
			rawMax === '' || rawMax === undefined ? fallback[1] : Number(rawMax);

		if (!Number.isNaN(min) && !Number.isNaN(max)) {
			return [Math.min(min, max), Math.max(min, max)];
		}
	}

	return fallback;
}

export function getRangeStep(min: number, max: number): number {
	const rangeSize = max - min;
	if (rangeSize <= 20) return 1;
	if (rangeSize <= 100) return Math.ceil(rangeSize / 20);
	return Math.ceil(rangeSize / 50);
}

export function formatRangeValue(value: number): string {
	return value.toLocaleString('en-US', { maximumFractionDigits: 0 });
}

export function isCompleteRangeFilterValue(value: unknown): boolean {
	if (!Array.isArray(value) || value.length < 2) {
		return false;
	}

	const min = coerceRangeNumber(value[0]);
	const max = coerceRangeNumber(value[1]);
	return min !== undefined && max !== undefined && min <= max;
}

export function coerceRangeNumber(value: unknown): number | undefined {
	if (typeof value === 'number' && !Number.isNaN(value)) {
		return value;
	}

	if (typeof value === 'string' && value.trim() !== '') {
		const parsed = Number(value);
		if (!Number.isNaN(parsed)) {
			return parsed;
		}
	}

	return undefined;
}

export function getColumnRangeBounds<TData>(
	column: Column<TData, unknown>,
	metaRange?: [number, number]
): { min: number; max: number; step: number } {
	let min = 0;
	let max = 100;

	if (metaRange && isValidRangeValue(metaRange)) {
		[min, max] = metaRange;
	} else {
		const faceted = column.getFacetedMinMaxValues?.();
		if (faceted && Array.isArray(faceted) && faceted.length === 2) {
			const facetMin = Number(faceted[0]);
			const facetMax = Number(faceted[1]);
			if (!Number.isNaN(facetMin) && !Number.isNaN(facetMax)) {
				min = facetMin;
				max = facetMax;
			}
		}
	}

	return { min, max, step: getRangeStep(min, max) };
}

export function formatDate(
	value: Date | string | number | undefined,
	options: Intl.DateTimeFormatOptions = {
		month: 'short',
		day: 'numeric',
		year: 'numeric'
	}
): string {
	if (value === undefined || value === null || value === '') {
		return '';
	}

	const date = value instanceof Date ? value : new Date(value);
	if (Number.isNaN(date.getTime())) {
		return '';
	}

	return new Intl.DateTimeFormat(undefined, options).format(date);
}

export function generateId({ length = 8 }: { length?: number } = {}): string {
	const alphabet = '0123456789abcdefghijklmnopqrstuvwxyz';

	if (typeof crypto !== 'undefined' && typeof crypto.getRandomValues === 'function') {
		const values = new Uint8Array(length);
		crypto.getRandomValues(values);
		return Array.from(values, (value) => alphabet[value % alphabet.length]).join('');
	}

	return Array.from({ length }, () => alphabet[Math.floor(Math.random() * alphabet.length)]).join(
		''
	);
}

import { dataTableConfig } from '$lib/config/data-table.js';
import type {
	ExtendedColumnFilter,
	ExtendedColumnSort,
	FilterVariant
} from '$lib/types/data-table.js';

export interface StateParser<T> {
	parse: (value: string) => T | null;
	serialize: (value: T) => string;
	eq: (left: T, right: T) => boolean;
}

export type FilterItemSchema = {
	id: string;
	value: string | string[];
	variant: FilterVariant;
	operator: (typeof dataTableConfig.operators)[number];
	filterId: string;
};

function getValidKeys(columnIds?: string[] | Set<string>): Set<string> | null {
	if (!columnIds) return null;
	return columnIds instanceof Set ? columnIds : new Set(columnIds);
}

function isSortingItem<TData>(
	item: unknown,
	validKeys: Set<string> | null
): item is ExtendedColumnSort<TData> {
	if (typeof item !== 'object' || item === null) return false;

	const candidate = item as { id?: unknown; desc?: unknown };
	return (
		typeof candidate.id === 'string' &&
		typeof candidate.desc === 'boolean' &&
		(!validKeys || validKeys.has(candidate.id))
	);
}

function isFilterItem<TData>(
	item: unknown,
	validKeys: Set<string> | null,
	validVariants: Set<string>,
	validOperators: Set<string>
): item is ExtendedColumnFilter<TData> {
	if (typeof item !== 'object' || item === null) return false;

	const candidate = item as {
		id?: unknown;
		value?: unknown;
		filterId?: unknown;
		variant?: unknown;
		operator?: unknown;
	};
	return (
		typeof candidate.id === 'string' &&
		(!validKeys || validKeys.has(candidate.id)) &&
		(typeof candidate.value === 'string' ||
			(Array.isArray(candidate.value) &&
				candidate.value.every((entry: unknown) => typeof entry === 'string'))) &&
		typeof candidate.filterId === 'string' &&
		typeof candidate.variant === 'string' &&
		validVariants.has(candidate.variant) &&
		typeof candidate.operator === 'string' &&
		validOperators.has(candidate.operator)
	);
}

export function getSortingStateParser<TData>(
	columnIds?: string[] | Set<string>
): StateParser<ExtendedColumnSort<TData>[]> {
	const validKeys = getValidKeys(columnIds);

	return {
		parse: (value) => {
			try {
				const parsed = JSON.parse(value);
				if (!Array.isArray(parsed)) return null;

				const sorting = parsed as unknown[];
				if (!sorting.every((item) => isSortingItem<TData>(item, validKeys))) return null;

				return sorting;
			} catch {
				return null;
			}
		},
		serialize: (value) => JSON.stringify(value),
		eq: (left, right) =>
			left.length === right.length &&
			left.every((item, index) => item.id === right[index]?.id && item.desc === right[index]?.desc)
	};
}

export function getFiltersStateParser<TData>(
	columnIds?: string[] | Set<string>
): StateParser<ExtendedColumnFilter<TData>[]> {
	const validKeys = getValidKeys(columnIds);
	const validVariants = new Set<string>(dataTableConfig.filterVariants);
	const validOperators = new Set<string>(dataTableConfig.operators);

	return {
		parse: (value) => {
			try {
				const parsed = JSON.parse(value);
				if (!Array.isArray(parsed)) return null;

				const filters = parsed as unknown[];
				if (
					!filters.every((item) =>
						isFilterItem<TData>(item, validKeys, validVariants, validOperators)
					)
				) {
					return null;
				}

				return filters;
			} catch {
				return null;
			}
		},
		serialize: (value) => JSON.stringify(value),
		eq: (left, right) =>
			left.length === right.length &&
			left.every((filter, index) => {
				const rightFilter = right[index];
				if (!rightFilter) return false;

				const leftValue = Array.isArray(filter.value) ? filter.value.join('\u0000') : filter.value;
				const rightValue = Array.isArray(rightFilter.value)
					? rightFilter.value.join('\u0000')
					: rightFilter.value;

				return (
					filter.id === rightFilter.id &&
					leftValue === rightValue &&
					filter.variant === rightFilter.variant &&
					filter.operator === rightFilter.operator &&
					filter.filterId === rightFilter.filterId
				);
			})
	};
}

