// ============================================
// Base Types
// ============================================

export type Direction = 'ltr' | 'rtl';

export interface Option {
	label: string;
	value: string;
}

export type RowHeightValue = 'short' | 'medium' | 'tall' | 'extra-tall';

export type DataGridSelectHitboxSize = 'default' | 'sm' | 'lg';

export interface CellSelectOption {
	label: string;
	value: string;
	icon?: Component;
	count?: number;
}

// ============================================
// Cell Types
// ============================================

export type CellOpts =
	| { variant: 'short-text' }
	| { variant: 'long-text' }
	| { variant: 'number'; min?: number; max?: number; step?: number }
	| { variant: 'select'; options: CellSelectOption[] }
	| { variant: 'multi-select'; options: CellSelectOption[] }
	| { variant: 'checkbox' }
	| { variant: 'date' }
	| { variant: 'url' }
	| {
			variant: 'row-select';
			enableRowMarkers?: boolean;
			readOnly?: boolean;
			hitboxSize?: DataGridSelectHitboxSize;
			debug?: boolean;
	  }
	| {
			variant: 'file';
			maxFileSize?: number;
			maxFiles?: number;
			accept?: string;
			multiple?: boolean;
	  };

export interface UpdateCell {
	rowIndex: number;
	columnId: string;
	value: unknown;
}

// ============================================
// Position & Selection Types
// ============================================

export interface CellPosition {
	rowIndex: number;
	columnId: string;
	/** Resolve display index after sort/filter; preferred over rowIndex when adding rows */
	rowId?: string;
}

export interface CellRange {
	start: CellPosition;
	end: CellPosition;
}

export interface SelectionState {
	selectedCells: Set<string>;
